using Microsoft.EntityFrameworkCore;
class MigrationRunner
{
    // EF Core 9 breaking change: Migrate() inside an explicit transaction now throws.
    // Apply migrations outside the transaction; EF manages its own transactions internally.
    void ApplyMigrations(AppDbContext db)
    {
        var strategy = db.Database.CreateExecutionStrategy();
        strategy.Execute(() =>
        {
            db.Database.Migrate();
        });
    }

    // EF Core 9 breaking change (Cosmos): Synchronous I/O is no longer supported.
    // All Cosmos queries must use async methods (ToListAsync, FirstOrDefaultAsync, etc.)
    async Task QueryCosmosAsync(CosmosDbContext cosmosDb)
    {
        // BEFORE (throws in EF Core 9):
        //   var orders = cosmosDb.Orders.ToList();
        //   var first = cosmosDb.Orders.First();

        // AFTER: use async equivalents
        var orders = await cosmosDb.Orders.ToListAsync();
        var first = await cosmosDb.Orders.FirstOrDefaultAsync();
    }
}

